(window.webpackJsonp=window.webpackJsonp||[]).push([[462],{1089:function(n,r){n.exports="\x3c!-- \r\ntitle: 03-React组件\r\nsort: \r\n--\x3e \r\n\r\n## 组件与props\r\n\r\n```react\r\n<script type=\"text/babel\">\r\n    function Hello(props) {\r\n        return <div>\r\n            <h1>Hello,{props.name}</h1>\r\n            <p>age: {props.age}</p>\r\n            <p>skill: Draw</p>\r\n        </div>\r\n    }\r\n\r\n    ReactDOM.render( \r\n        <Hello name=\"fzf\" age=\"19\" />\r\n        , document.getElementById('app'));\r\n<\/script>\r\n```\r\n\r\n## 组件类\r\n\r\n```react\r\nclass Hellofzf extends React.Component {\r\n    render() {\r\n        return <div>\r\n            <h1>Hello,{this.props.name}</h1>\r\n            <p>age: {this.props.age}</p>\r\n            <p>skill: Draw</p>\r\n        </div>\r\n    }\r\n}\r\nReactDOM.render(\r\n    <Hellofzf name=\"fzf\" age=\"19\" />\r\n    , document.getElementById('app'));\r\n```\r\n\r\n## 生命周期\r\n\r\n> chrome console\r\n\r\n![image-20201125152041383](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2020/20201125152041.png)\r\n\r\n```react\r\n// 组件名称必须大写\r\nclass Hello extends React.Component {\r\n    // 构造函数，传给父类\r\n    constructor(props) {\r\n        console.log('初始化阶段')\r\n        // 初始化props\r\n        super(props)\r\n        // 初始化状态\r\n        this.state = {\r\n            name: 'fzf',\r\n            age: 19\r\n        }\r\n    }\r\n    componentWillMount() {\r\n        console.log('组件加载前');\r\n    }\r\n    // 这时调用render加载组件\r\n    componentDidMount() {\r\n        console.log('组件加载后')\r\n    }\r\n    // 更改state的值\r\n    updateUser = () => {\r\n        this.setState({\r\n            name: 'Tim',\r\n            age: 20\r\n        })\r\n    }\r\n    shouldComponentUpdate() {\r\n        console.log('数据是否需要更新')\r\n        return true\r\n    }\r\n    componentWillUpdate() {\r\n        console.log('数据即将更新')\r\n    }\r\n    componentDidUpdate() {\r\n        console.log('数据已经更新')\r\n    }\r\n    render() {\r\n        console.log('组件加载或数据更新')\r\n        return <div>\r\n            <h1>Hello,{this.state.name}</h1>\r\n            <p>age: {this.state.age}</p>\r\n            <p>skill: Draw</p>\r\n            <button onClick={this.updateUser}>Update</button>\r\n        </div>\r\n    }\r\n}\r\nReactDOM.render(\r\n    <Hello />\r\n    , document.getElementById('app'));\r\n```\r\n\r\n"}}]);